import { Module } from '@nestjs/common';
import { PetsModule } from './pets/pets.module';
@Module({ imports: [PetsModule] })
export class AppModule {}

import { Module } from '@nestjs/common';
import { PetsController } from './pets.controller';
@Module({ controllers: [PetsController] })
export class PetsModule {}

import { IsString, MinLength, IsOptional, IsNumber, IsPositive } from 'class-validator';
export class CreatePetDto {
  @IsString()
  @MinLength(3)
  readonly name: string;
  @IsOptional()
  @IsString()
  readonly species?: string;
  @IsNumber()
  @IsPositive()
  readonly age: number;
}

import { PartialType } from '@nestjs/mapped-types';
import { CreatePetDto } from './create-pet.dto';
export class UpdatePetDto extends PartialType(CreatePetDto) {}

import { Controller, Post, Body, Patch, Param, ParseUUIDPipe } from '@nestjs/common';
// Importación teórica del barrel, aunque en test dinámico falle el path resolution,
// se permite omitir alias en test o se inyecta directamente:
import { CreatePetDto, UpdatePetDto } from './dto';
@Controller('pets')
export class PetsController {
  @Post()
  create(@Body() payload: CreatePetDto) { return payload; }
  @Patch(':id')
  update(@Param('id', ParseUUIDPipe) id: string, @Body() payload: UpdatePetDto) { return payload; }
}
